void RLTaskSceneEntityJointHintSchema::setEffortLimit(double value)
{
    m_Effort_limit = value;
}

bool RLTaskSceneEntityJointHintSchema::effortLimitIsSet() const
{
    return m_Effort_limit.has_value();
}

void RLTaskSceneEntityJointHintSchema::unsetEffort_limit()
{
    m_Effort_limit.reset();
}

